"""Gateway layer — entry point and request routing for document management."""
import time
import processor

# Client-side cache of document timestamps (simulates browser/client state)
_client_timestamps = {}  # doc_id -> timestamp when client last saw the doc


def reset_client_cache():
    """Reset client-side cache."""
    global _client_timestamps
    _client_timestamps = {}


def create_document(title, content, author, role):
    """Create a new document."""
    timestamp = time.time()  # Full float precision (e.g., 1710244800.123456)
    doc = processor.create_document(title, content, author, role, timestamp)
    # Cache the timestamp for later conflict detection
    _client_timestamps[doc["doc_id"]] = timestamp
    return {"status": "ok", "doc": doc}


def update_document(doc_id, content, author, role, version):
    """Update a document, creating a new version.
    Version comes from client request data (always a string in real usage).
    """
    timestamp = time.time()
    # BUG 1 (root cause): version from request data is a string.
    # We pass it through without converting to int.
    # This causes string comparisons downstream and stores strings in datastore.
    result = processor.update_document(doc_id, content, author, role, version, timestamp)
    if result.get("error") is None:
        # Update client cache with new timestamp
        _client_timestamps[doc_id] = timestamp
    return {"status": "ok", "result": result}


def get_document(doc_id):
    """Get the current version of a document."""
    doc = processor.get_document(doc_id)
    return {"status": "ok", "doc": doc}


def get_version_history(doc_id):
    """Get all versions of a document."""
    history = processor.get_version_history(doc_id)
    return {"status": "ok", "history": history}


def check_permission(doc_id, role, action):
    """Check if a role has permission to perform an action on a document."""
    # BUG 2 (propagation): role comes from user session with original casing
    # e.g., "Editor", "Admin", "Viewer". Passed through as-is.
    allowed = processor.check_permission(doc_id, role, action)
    return {"status": "ok", "allowed": allowed}


def get_latest_version_number(doc_id):
    """Get the latest version number of a document."""
    version = processor.get_latest_version(doc_id)
    return {"status": "ok", "version": version}


def check_modified_since(doc_id):
    """Check if a document has been modified since the client last saw it.
    Uses the cached timestamp from when the client last created/updated the doc.
    Returns True if the document was modified by someone else, False otherwise.
    """
    # BUG 3 (propagation): _client_timestamps stores the original float timestamp
    # from time.time(), but processor truncated it to int before storing in datastore.
    # So client has float 1710244800.789 but datastore has int 1710244800.
    client_ts = _client_timestamps.get(doc_id)
    if client_ts is None:
        return {"status": "ok", "modified": True}  # No cache = assume modified
    modified = processor.check_modified_since(doc_id, client_ts)
    return {"status": "ok", "modified": modified}


def list_documents():
    """List all documents."""
    docs = processor.list_documents()
    return {"status": "ok", "docs": docs}

seed_files.processor.py:
"""Processor layer — business logic for document management."""
import validator
import datastore

# Activity log: records document operations
_activity_log = []


def reset_activity_log():
    """Reset the activity log."""
    global _activity_log
    _activity_log = []


def create_document(title, content, author, role, timestamp):
    """Create a new document with version 1."""
    # BUG 3 (root cause): Truncate timestamp to int for activity log.
    # This truncated value also gets stored in datastore.
    # But gateway caches the original float for later conflict checks.
    ts_for_storage = int(timestamp)  # e.g., 1710244800.789 -> 1710244800

    doc_id = datastore.store_document(title, content, author, 1, ts_for_storage)
    _activity_log.append({
        "action": "create",
        "doc_id": doc_id,
        "author": author,
        "timestamp": ts_for_storage,
    })
    return {"doc_id": doc_id, "version": 1}


def update_document(doc_id, content, author, role, version, timestamp):
    """Update a document, creating a new version."""
    # Check permission (BUG 2 propagation: role passes through unmodified)
    if not validator.check_edit_permission(doc_id, role):
        return {"error": "permission_denied"}

    # BUG 1 (propagation): version passes through to validator unmodified
    if not validator.validate_version_order(doc_id, version):
        return {"error": "version_order", "detail": "new version must be greater than current"}

    # BUG 3 (propagation): Truncate timestamp for storage
    ts_for_storage = int(timestamp)

    # Store the new version (BUG 1 propagation: string version goes to datastore)
    new_version = datastore.add_version(doc_id, content, author, version, ts_for_storage)
    _activity_log.append({
        "action": "update",
        "doc_id": doc_id,
        "author": author,
        "version": new_version,
        "timestamp": ts_for_storage,
    })
    return {"doc_id": doc_id, "version": new_version}


def get_document(doc_id):
    """Get the latest version of a document."""
    return datastore.get_document(doc_id)


def get_version_history(doc_id):
    """Get all versions of a document, sorted by version number."""
    return datastore.get_version_history(doc_id)


def get_latest_version(doc_id):
    """Get the latest version number of a document."""
    return datastore.get_latest_version(doc_id)


def check_permission(doc_id, role, action):
    """Check if a role has permission for an action."""
    # BUG 2 (propagation): passes role through without normalizing
    if action == "edit":
        return validator.check_edit_permission(doc_id, role)
    elif action == "delete":
        return validator.check_delete_permission(role)
    elif action == "view":
        return validator.check_view_permission(role)
    return False


def check_modified_since(doc_id, client_timestamp):
    """Check if document was modified since the given timestamp."""
    # BUG 3 (propagation): client_timestamp is float, passes through to validator
    return validator.check_modified_since(doc_id, client_timestamp)


def list_documents():
    """List all documents."""
    return datastore.list_documents()


def get_activity_log():
    """Get the activity log."""
    return list(_activity_log)

seed_files.datastore.py:
"""Datastore layer — persistence for document management."""

# In-memory storage
_documents = {}  # doc_id -> latest document state
_versions = {}   # doc_id -> list of version records
_next_id = 1


def reset():
    """Reset all storage."""
    global _documents, _versions, _next_id
    _documents = {}
    _versions = {}
    _next_id = 1


def store_document(title, content, author, version, timestamp):
    """Store a new document. Returns doc_id."""
    global _next_id
    doc_id = _next_id
    _next_id += 1
    _documents[doc_id] = {
        "doc_id": doc_id,
        "title": title,
        "content": content,
        "author": author,
        "version": version,
        "timestamp": timestamp,  # Stored as int (truncated by processor)
    }
    _versions[doc_id] = [{
        "version": version,
        "content": content,
        "author": author,
        "timestamp": timestamp,
    }]
    return doc_id


def add_version(doc_id, content, author, new_version, timestamp):
    """Add a new version to a document. Returns the new version."""
    if doc_id not in _documents:
        raise KeyError(f"Document {doc_id} not found")

    # BUG 1 (manifestation): new_version may be a string from gateway.
    # We store it as-is, so get_latest_version will return a string.
    # This breaks all downstream comparisons.
    _documents[doc_id]["content"] = content
    _documents[doc_id]["author"] = author
    _documents[doc_id]["version"] = new_version
    _documents[doc_id]["timestamp"] = timestamp

    _versions[doc_id].append({
        "version": new_version,
        "content": content,
        "author": author,
        "timestamp": timestamp,
    })
    return new_version


def get_document(doc_id):
    """Get the latest state of a document."""
    return _documents.get(doc_id)


def get_version_history(doc_id):
    """Get all versions of a document, sorted by version number."""
    versions = _versions.get(doc_id, [])
    # BUG 1 (manifestation): If version numbers are strings mixed with ints,
    # sorting raises TypeError in Python 3 or gives wrong order.
    try:
        return sorted(versions, key=lambda v: v["version"])
    except TypeError:
        # Mixed types: fall back to string sort (also wrong for multi-digit)
        return sorted(versions, key=lambda v: str(v["version"]))


def get_latest_version(doc_id):
    """Get the latest version number of a document."""
    doc = _documents.get(doc_id)
    if doc is None:
        return None
    return doc["version"]


def list_documents():
    """List all documents."""
    return list(_documents.values())
